// MARK: - Models

enum TransactionType: String, Codable {
    case deposit
    case withdrawal
    case transfer
    case payment
}

enum TransactionStatus: String, Codable {
    case pending
    case completed
    case failed
    case cancelled
}

enum Currency: String, Codable {
    case usd = "USD"
    case eur = "EUR"
    case gbp = "GBP"
}

struct Transaction: Codable, Identifiable {
    let id: UUID
    let type: TransactionType
    let amount: Decimal
    let currency: Currency
    let fromAccountId: String
    let toAccountId: String?
    let description: String
    let timestamp: Date
    var status: TransactionStatus
    let referenceNumber: String
    
    init(type: TransactionType, amount: Decimal, currency: Currency, fromAccountId: String, toAccountId: String? = nil, description: String) {
        self.id = UUID()
        self.type = type
        self.amount = amount
        self.currency = currency
        self.fromAccountId = fromAccountId
        self.toAccountId = toAccountId
        self.description = description
        self.timestamp = Date()
        self.status = .pending
        self.referenceNumber = Self.generateReferenceNumber()
    }
    
    private static func generateReferenceNumber() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        let random = Int.random(in: 1000...9999)
        return "TXN-\(timestamp)-\(random)"
    }
}

struct Account: Codable, Identifiable {
    let id: String
    let accountNumber: String
    let accountHolderName: String
    var balance: Decimal
    let currency: Currency
    let createdAt: Date
    var isActive: Bool
    var transactions: [Transaction]
    
    var maskedAccountNumber: String {
        let suffix = String(accountNumber.suffix(4))
        return "****\(suffix)"
    }
}

struct TransactionResult {
    let success: Bool
    let transaction: Transaction
    let message: String
    let updatedBalance: Decimal?
}

// MARK: - Encryption Service

final class EncryptionService {
    
    static let shared = EncryptionService()
    
    private let keychainServiceName = "com.bankingapp.encryption"
    private let symmetricKeyTag = "com.bankingapp.symmetrickey"
    
    private init() {
        ensureEncryptionKeyExists()
    }
    
    // MARK: - Key Management
    
    private func ensureEncryptionKeyExists() {
        if retrieveKeyFromKeychain() == nil {
            let key = SymmetricKey(size: .bits256)
            storeKeyInKeychain(key)
        }
    }
    
    private func storeKeyInKeychain(_ key: SymmetricKey) {
        let keyData = key.withUnsafeBytes { Data($0) }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServiceName,
            kSecAttrAccount as String: symmetricKeyTag,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        
        if status != errSecSuccess {
            print("Failed to store encryption key in keychain: \(status)")
        }
    }
    
    private func retrieveKeyFromKeychain() -> SymmetricKey? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainServiceName,
            kSecAttrAccount as String: symmetricKeyTag,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let keyData = result as? Data else {
            return nil
        }
        
        return SymmetricKey(data: keyData)
    }
    
    private func getEncryptionKey() -> SymmetricKey {
        if let key = retrieveKeyFromKeychain() {
            return key
        }
        let key = SymmetricKey(size: .bits256)
        storeKeyInKeychain(key)
        return key
    }
    
    // MARK: - Encryption / Decryption
    
    func encrypt(data: Data) throws -> Data {
        let key = getEncryptionKey()
        let sealedBox = try AES.GCM.seal(data, using: key)
        guard let combined = sealedBox.combined else {
            throw EncryptionError.encryptionFailed
        }
        return combined
    }
    
    func decrypt(data: Data) throws -> Data {
        let key = getEncryptionKey()
        let sealedBox = try AES.GCM.SealedBox(combined: data)
        return try AES.GCM.open(sealedBox, using: key)
    }
    
    func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw EncryptionError.invalidInput
        }
        return try encrypt(data: data)
    }
    
    func decryptToString(data: Data) throws -> String {
        let decryptedData = try decrypt(data: data)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw EncryptionError.decryptionFailed
        }
        return string
    }
    
    func hashData(_ data: Data) -> String {
        let digest = SHA256.hash(data: data)
        return digest.compactMap { String(format: "%02x", $0) }.joined()
    }
    
    func encryptModel<T: Encodable>(_ model: T) throws -> Data {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let jsonData = try encoder.encode(model)
        return try encrypt(data: jsonData)
    }
    
    func decryptModel<T: Decodable>(_ type: T.Type, from data: Data) throws -> T {
        let decryptedData = try decrypt(data: data)
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode(type, from: decryptedData)
    }
}

enum EncryptionError: Error, LocalizedError {
    case encryptionFailed
    case decryptionFailed
    case invalidInput
    case keyNotFound
    
    var errorDescription: String? {
        switch self {
        case .encryptionFailed: return "Failed to encrypt data"
        case .decryptionFailed: return "Failed to decrypt data"
        case .invalidInput: return "Invalid input data"
        case .keyNotFound: return "Encryption key not found"
        }
    }
}

// MARK: - Secure Storage

final class SecureStorageService {
    
    static let shared = SecureStorageService()
    private let encryption = EncryptionService.shared
    private let fileManager = FileManager.default
    
    private var storageDirectory: URL {
        let paths = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask)
        let directory = paths[0].appendingPathComponent("SecureBankingData", isDirectory: true)
        if !fileManager.fileExists(atPath: directory.path) {
            try? fileManager.createDirectory(at: directory, withIntermediateDirectories: true)
        }
        return directory
    }
    
    private init() {}
    
    func saveAccount(_ account: Account) throws {
        let encryptedData = try encryption.encryptModel(account)
        let fileURL = storageDirectory.appendingPathComponent("account_\(account.id).enc")
        try encryptedData.write(to: fileURL, options: .completeFileProtection)
    }
    
    func loadAccount(id: String) throws -> Account {
        let fileURL = storageDirectory.appendingPathComponent("account_\(id).enc")
        let encryptedData = try Data(contentsOf: fileURL)
        return try encryption.decryptModel(Account.self, from: encryptedData)
    }
    
    func saveTransactionLog(_ transactions: [Transaction], forAccountId accountId: String) throws {
        let encryptedData = try encryption.encryptModel(transactions)
        let fileURL = storageDirectory.appendingPathComponent("transactions_\(accountId).enc")
        try encryptedData.write(to: fileURL, options: .completeFileProtection)
    }
    
    func loadTransactionLog(forAccountId accountId: String) throws -> [Transaction] {
        let fileURL = storageDirectory.appendingPathComponent("transactions_\(accountId).enc")
        let encryptedData = try Data(contentsOf: fileURL)
        return try encryption.decryptModel([Transaction].self, from: encryptedData)
    }
    
    func deleteAllData() throws {
        let contents = try fileManager.contentsOfDirectory(at: storageDirectory, includingPropertiesForKeys: nil)
        for fileURL in contents {
            try fileManager.removeItem(at: fileURL)
        }
    }
}

// MARK: - Transaction Validator

struct TransactionValidator {
    
    enum ValidationError: Error, LocalizedError {
        case insufficientFunds(available: Decimal, requested: Decimal)
        case invalidAmount
        case accountInactive
        case sameAccountTransfer
        case dailyLimitExceeded(limit: Decimal)
        case invalidAccount
        
        var errorDescription: String? {
            switch self {
            case .insufficientFunds(let available, let requested):
                return "Insufficient funds. Available: \(available), Requested: \(requested)"
            case .invalidAmount:
                return "Transaction amount must be greater than zero"
            case .accountInactive:
                return "Account is inactive"
            case .sameAccountTransfer:
                return "Cannot transfer to the same account"
            case .dailyLimitExceeded(let limit):
                return "Daily transaction limit of \(limit) exceeded"
            case .invalidAccount:
                return "Invalid account"
            }
        }
    }
    
    private let dailyTransactionLimit: Decimal = 50000.00
    
    func validate(transaction: Transaction, account: Account) -> Result<Void, ValidationError> {
        guard account.isActive else {
            return .failure(.accountInactive)
        }
        
        guard transaction.amount > 0 else {
            return .failure(.invalidAmount)
        }
        
        if transaction.type == .transfer, transaction.toAccountId == transaction.fromAccountId {
            return .failure(.sameAccountTransfer)
        }
        
        if transaction.type == .withdrawal || transaction.type == .transfer || transaction.type == .payment {
            guard account.balance >= transaction.amount else {
                return .failure(.insufficientFunds(available: account.balance, requested: transaction.amount))
            }
        }
        
        let todayTotal = calculateDailyTotal(for: account)
        if todayTotal + transaction.amount > dailyTransactionLimit {
            return .failure(.dailyLimitExceeded(limit: dailyTransactionLimit))
        }
        
        return .success(())
    }
    
    private func calculateDailyTotal(for account: Account) -> Decimal {
        let calendar = Calendar.current
        let today = calendar.startOfDay(for: Date())
        
        return account.transactions
            .filter { calendar.isDate($0.timestamp, inSameDayAs: today) }
            .filter { $0.type != .deposit }
            .filter { $0.status == .completed }
            .reduce(Decimal.zero) { $0 + $1.amount }
    }
}

// MARK: - Transaction Processor

final class TransactionProcessor {
    
    static let shared = TransactionProcessor()
    
    private let validator = TransactionValidator()
    private let secureStorage = SecureStorageService.shared
    private let encryption = EncryptionService.shared
    private let transactionQueue = DispatchQueue(label: "com.bankingapp.transactionQueue", attributes: .concurrent)
    
    private var accounts: [String: Account] = [:]
    private let accountsLock = NSLock()
    
    private init() {}
    
    // MARK: - Account Management
    
    func createAccount(holderName: String, initialBalance: Decimal, currency: Currency) -> Account {
        let accountNumber = generateAccountNumber()
        let account = Account(
            id: UUID().uuidString,
            accountNumber: accountNumber,
            accountHolderName: holderName,
            balance: initialBalance,
            currency: currency,
            createdAt: Date(),
            isActive: true,
            transactions: []
        )
        
        accountsLock.lock()
        accounts[account.id] = account
        accountsLock.unlock()
        
        try? secureStorage.saveAccount(account)
        
        return account
    }
    
    func getAccount(id: String) -> Account? {
        accountsLock.lock()
        defer { accountsLock.unlock() }
        
        if let account = accounts[id] {
            return account
        }
        
        if let account = try? secureStorage.loadAccount(id: id) {
            accounts[id] = account
            return account
        }
        
        return nil
    }
    
    func getBalance(accountId: String) -> Decimal? {
        return getAccount(id: accountId)?.balance
    }
    
    // MARK: - Transaction Processing
    
    func processTransaction(_ transaction: Transaction, completion: @escaping (TransactionResult) -> Void) {
        transactionQueue.async(flags: .barrier) { [weak self] in
            guard let self = self else { return }
            
            self.accountsLock.lock()
            guard var account = self.accounts[transaction.fromAccountId] else {
                self.accountsLock.unlock()
                var failedTransaction = transaction
                failedTransaction.status = .failed
                completion(TransactionResult(
                    success: false,
                    transaction: failedTransaction,
                    message: "Account not found",
                    updatedBalance: nil
                ))
                return
            }
            self.accountsLock.unlock()
            
            let validationResult = self.validator.validate(transaction: transaction, account: account)
            
            switch validationResult {
            case .failure(let error):
                var failedTransaction = transaction
                failedTransaction.status = .failed
                completion(TransactionResult(
                    success: false,
                    transaction: failedTransaction,
                    message: error.localizedDescription,
                    updatedBalance: account.balance
                ))
                
            case .success:
                var processedTransaction = transaction
                
                switch transaction.type {
                case .deposit:
                    account.balance += transaction.amount
                    processedTransaction.status = .completed
                    
                case .withdrawal:
                    account.balance -= transaction.amount
                    processedTransaction.status = .completed
                    
                case .transfer:
                    account.balance -= transaction.amount
                    if let toAccountId = transaction.toAccountId {
                        self.accountsLock.lock()
                        self.accounts[toAccountId]?.balance += transaction.amount
                        if let toAccount = self.accounts[toAccountId] {
                            try? self.secureStorage.saveAccount(toAccount)
                        }
                        self.accountsLock.unlock()
                    }
                    processedTransaction.status = .completed
                    
                case .payment:
                    account.balance -= transaction.amount
                    processedTransaction.status = .completed
                }
                
                account.transactions.append(processedTransaction)
                
                self.accountsLock.lock()
                self.accounts[account.id] = account
                self.accountsLock.unlock()
                
                self.logTransaction(processedTransaction)
                
                try? self.secureStorage.saveAccount(account)
                
                completion(TransactionResult(
                    success: true,
                    transaction: processedTransaction,
                    message: "Transaction completed successfully",
                    updatedBalance: account.balance
                ))
            }
        }
    }
    
    func deposit(amount: Decimal, toAccountId: String, description: String = "Deposit", completion: @escaping (TransactionResult) -> Void) {
        let transaction = Transaction(
            type: .deposit,
            amount: amount,
            currency: .usd,
            fromAccountId: toAccountId,
            description: description
        )
        processTransaction(transaction, completion: completion)
    }
    
    func withdraw(amount: Decimal, fromAccountId: String, description: String = "Withdrawal", completion: @escaping (TransactionResult) -> Void) {
        let transaction = Transaction(
            type: .withdrawal,
            amount: amount,
            currency: .usd,
            fromAccountId: fromAccountId,
            description: description
        )
        processTransaction(transaction, completion: completion)
    }
    
    func transfer(amount: Decimal, fromAccountId: String, toAccountId: String, description: String = "Transfer", completion: @escaping (TransactionResult) -> Void) {
        let transaction = Transaction(
            type: .transfer,
            amount: amount,
            currency: .usd,
            fromAccountId: fromAccountId,
            toAccountId: toAccountId,
            description: description
        )
        processTransaction(transaction, completion: completion)
    }
    
    func makePayment(amount: Decimal, fromAccountId: String, description: String, completion: @escaping (TransactionResult) -> Void) {
        let transaction = Transaction(
            type: .payment,
            amount: amount,
            currency: .usd,
            fromAccountId: fromAccountId,
            description: description
        )
        processTransaction(transaction, completion: completion)
    }
    
    // MARK: - Transaction History
    
    func getTransactionHistory(forAccountId accountId: String) -> [Transaction] {
        guard let account = getAccount(id: accountId) else { return [] }
        return account.transactions.sorted { $0.timestamp > $1.timestamp }
    }
    
    func getTransactionHistory(forAccountId accountId: String, type: TransactionType) -> [Transaction] {
        return getTransactionHistory(forAccountId: accountId).filter { $0.type == type }
    }
    
    func getTransactionHistory(forAccountId accountId: String, from startDate: Date, to endDate: Date) -> [Transaction] {
        return getTransactionHistory(forAccountId: accountId).filter {
            $0.timestamp >= startDate && $0.timestamp <= endDate
        }
    }
    
    // MARK: - Helpers
    
    private func generateAccountNumber() -> String {
        let digits = (0..<12).map { _ in String(Int.random(in: 0...9)) }.joined()
        return digits
    }
    
    private func logTransaction(_ transaction: Transaction) {
        let transactionHash = encryption.hashData(
            "\(transaction.id)\(transaction.amount)\(transaction.timestamp)".data(using: .utf8)!
        )
        
        print("[AUDIT] Transaction \(transaction.referenceNumber) | Type: \(transaction.type.rawValue) | Status: \(transaction.status.rawValue) | Hash: \(transactionHash)")
    }
}

// MARK: - Account Balance View Model

import SwiftUI

@MainActor
final class AccountViewModel: ObservableObject {
    
    @Published var account: Account?
    @Published var transactions: [Transaction] = []
    @Published var isLoading = false
    @Published var errorMessage: String?
    @Published var successMessage: String?
    @Published var formattedBalance: String = "$0.00"
    
    private let processor = TransactionProcessor.shared
    
    func loadAccount(id: String) {
        isLoading = true
        errorMessage = nil
        
        if let account = processor.getAccount(id: id) {
            self.account = account
            self.transactions = processor.getTransactionHistory(forAccountId: id)
            self.formattedBalance = formatCurrency(account.balance, currency: account.currency)
        } else {
            errorMessage = "Account not found"
        }
        
        isLoading = false
    }
    
    func createDemoAccount() {
        let account = processor.createAccount(
            holderName: "John Doe",
            initialBalance: 10000.00,
            currency: .usd
        )
        self.account = account
        self.formattedBalance = formatCurrency(account.balance, currency: account.currency)
        self.transactions = []
    }
    
    func performDeposit(amount: Decimal) {
        guard let accountId = account?.id else { return }
        isLoading = true
        errorMessage = nil
        successMessage = nil
        
        processor.deposit(amount: amount, toAccountId: accountId, description: "Mobile Deposit") { [weak self] result in
            DispatchQueue.main.async {
                self?.handleTransactionResult(result)
            }
        }
    }
    
    func performWithdrawal(amount: Decimal) {
        guard let accountId = account?.id else { return }
        isLoading = true
        errorMessage = nil
        successMessage = nil
        
        processor.withdraw(amount: amount, fromAccountId: accountId, description: "ATM Withdrawal") { [weak self] result in
            DispatchQueue.main.async {
                self?.handleTransactionResult(result)
            }
        }
    }
    
    func performTransfer(amount: Decimal, toAccountId: String) {
        guard let accountId = account?.id else { return }
        isLoading = true
        errorMessage = nil
        successMessage = nil
        
        processor.transfer(amount: amount, fromAccountId: accountId, toAccountId: toAccountId, description: "Fund Transfer") { [weak self] result in
            DispatchQueue.main.async {
                self?.handleTransactionResult(result)
            }
        }
    }
    
    func performPayment(amount: Decimal, description: String) {
        guard let accountId = account?.id else { return }
        isLoading = true
        errorMessage = nil
        successMessage = nil
        
        processor.makePayment(amount: amount, fromAccountId: accountId, description: description) { [weak self] result in
            DispatchQueue.main.async {
                self?.handleTransactionResult(result)
            }
        }
    }
    
    private func handleTransactionResult(_ result: TransactionResult) {
        isLoading = false
        
        if result.success {
            successMessage = result.message
            if let updatedBalance = result.updatedBalance, let currency = account?.currency {
                formattedBalance = formatCurrency(updatedBalance, currency: currency)
            }
            if let accountId = account?.id {
                account = processor.getAccount(id: accountId)
                transactions = processor.getTransactionHistory(forAccountId: accountId)
            }
        } else {
            errorMessage = result.message
        }
    }
    
    private func formatCurrency(_ amount: Decimal, currency: Currency) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        switch currency {
        case .usd: formatter.currencyCode = "USD"
        case .eur: formatter.currencyCode = "EUR"
        case .gbp: formatter.currencyCode = "GBP"
        }
        return formatter.string(from: amount as NSDecimalNumber) ?? "$0.00"
    }
}

