                    .textFieldStyle(RoundedBorderTextFieldStyle())
                    .padding(.horizontal)
                
                Button(action: action) {
                    Text("Confirm \(title)")
                        .fontWeight(.semibold)
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(Color.blue)
                        .foregroundColor(.white)
                        .cornerRadius(12)
                }
                .padding(.horizontal)
                .disabled(transactionAmount.isEmpty)
                
                Spacer()
            }
            .padding(.top, 30)
            .navigationBarItems(trailing: Button("Cancel") {
                showingDepositSheet = false
                showingWithdrawSheet = false
                transactionAmount = ""
            })
        }
    }
    
    private var paymentSheet: some View {
        NavigationView {
            VStack(spacing: 20) {
                Text("Make Payment")
                    .font(.title2)
                    .fontWeight(.bold)
                
                TextField("Amount", text: $transactionAmount)
                    .keyboardType(.decimalPad)
                    .textFieldStyle(RoundedBorderTextFieldStyle())
                    .padding(.horizontal)
                
                TextField("Description", text: $paymentDescription)
                    .textFieldStyle(RoundedBorderTextFieldStyle())
                    .padding(.horizontal)
                
                Button(action: {
                    if let amount = Decimal(string: transactionAmount) {
                        viewModel.performPayment(amount: amount, description: paymentDescription.isEmpty ? "Payment" : paymentDescription)
                        showingPaymentSheet = false
                        transactionAmount = ""
                        paymentDescription = ""
                    }
                }) {
                    Text("Confirm Payment")
                        .fontWeight(.semibold)
                        .frame(maxWidth: .infinity)
                        .padding()
                        .background(Color.purple)
                        .foregroundColor(.white)
                        .cornerRadius(12)
                }
                .padding(.horizontal)
                .disabled(transactionAmount.isEmpty)
                
                Spacer()
            }
            .padding(.top, 30)
            .navigationBarItems(trailing: Button("Cancel") {
                showingPaymentSheet = false
                transactionAmount = ""
                paymentDescription = ""
            })
        }
    }
}

struct TransactionRowView: View {
    let transaction: Transaction
    
    var body: some View {
        HStack(spacing: 12) {
            transactionIcon
            
            VStack(alignment: .leading, spacing: 4) {
                Text(transaction.description)
                    .font(.subheadline)
                    .fontWeight(.medium)
                
                Text(formattedDate)
                    .font(.caption)
                    .foregroundColor(.secondary)
                
                Text(transaction.referenceNumber)
                    .font(.caption2)
                    .foregroundColor(.secondary)
            }
            
            Spacer()
            
            VStack(alignment: .trailing, spacing: 4) {
                Text(formattedAmount)
                    .font(.subheadline)
                    .fontWeight(.semibold)
                    .foregroundColor(amountColor)
                
                statusBadge
            }
        }
        .padding()
        .background(Color(.systemGray6))
        .cornerRadius(12)
    }
    
    private var transactionIcon: some View {
        ZStack {
            Circle()
                .fill(iconColor.opacity(0.15))
                .frame(width: 40, height: 40)
            
            Image(systemName: iconName)
                .foregroundColor(iconColor)
                .font(.system(size: 16, weight: .semibold))
        }
    }
    
    private var statusBadge: some View {
        Text(transaction.status.rawValue.capitalized)
            .font(.caption2)
            .fontWeight(.medium)
            .padding(.horizontal, 6)
            .padding(.vertical, 2)
            .background(statusColor.opacity(0.15))
            .foregroundColor(statusColor)
            .cornerRadius(4)
    }
    
    private var iconName: String {
        switch transaction.type {
        case .deposit: return "arrow.down.left"
        case .withdrawal: return "arrow.up.right"
        case .transfer: return "arrow.left.arrow.right"
        case .payment: return "creditcard"
        }
    }
    
    private var iconColor: Color {
        switch transaction.type {
        case .deposit: return .green
        case .withdrawal: return .orange
        case .transfer: return .blue
        case .payment: return .purple
        }
    }
    
    private var amountColor: Color {
        transaction.type == .deposit ? .green : .red
    }
    
    private var statusColor: Color {
        switch transaction.status {
        case .completed: return .green
        case .pending: return .orange
        case .failed: return .red
        case .cancelled: return .gray
        }
    }
    
    private var formattedAmount: String {
        let sign = transaction.type == .deposit ? "+" : "-"
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = transaction.currency.rawValue
        let amount = formatter.string(from: transaction.amount as NSDecimalNumber) ?? "$0.00"
        return "\(sign)\(amount)"
    }
    
    private var formattedDate: String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter.string(from: transaction.timestamp)
    }
}

