// MARK: - Audit Logger

final class AuditLogger {
    
    static let shared = AuditLogger()
    private let encryption = EncryptionService.shared
    private let logQueue = DispatchQueue(label: "com.bankingapp.auditlog")
    
    private init() {}
    
    func log(event: String, details: [String: String] = [:], severity: LogSeverity = .info) {
        logQueue.async { [weak self] in
            let entry = AuditEntry(
                timestamp: Date(),
                event: event,
                details: details,
                severity: severity
            )
            
            let entryString = "\(entry.timestamp) [\(entry.severity.rawValue.uppercased())] \(entry.event) | \(entry.details)"
            let hash = self?.encryption.hashData(entryString.data(using: .utf8)!) ?? "N/A"
            
            #if DEBUG
            print("[AUDIT-\(entry.severity.rawValue.uppercased())] \(entry.event) | Hash: \(hash)")
            #endif
        }
    }
    
    enum LogSeverity: String {
        case info
        case warning
        case error
        case critical
    }
    
    private struct AuditEntry {
        let timestamp: Date
        let event: String
        let details: [String: String]
        let severity: LogSeverity
    }
}

// MARK: - Session Security Manager

final class SessionSecurityManager {
    
    static let shared = SessionSecurityManager()
    
    private var sessionToken: String?
    private var sessionExpiry: Date?
    private let sessionDuration: TimeInterval = 900 // 15 minutes
    private let encryption = EncryptionService.shared
    
    private init() {}
    
    func createSession(userId: String) -> String {
        let tokenData = "\(userId)-\(UUID().uuidString)-\(Date().timeIntervalSince1970)"
        let token = encryption.hashData(tokenData.data(using: .utf8)!)
        
        sessionToken = token
        sessionExpiry = Date().addingTimeInterval(sessionDuration)
        
        AuditLogger.shared.log(event: "Session created", details: ["userId": userId])
        
        return token
    }
    
    func isSessionValid() -> Bool {
        guard let expiry = sessionExpiry, let _ = sessionToken else {
            return false
        }
        return Date() < expiry
    }
    
    func refreshSession() {
        guard isSessionValid() else { return }
        sessionExpiry = Date().addingTimeInterval(sessionDuration)
    }
    
    func invalidateSession() {
        sessionToken = nil
        sessionExpiry = nil
        AuditLogger.shared.log(event: "Session invalidated")
    }
    
    func validateToken(_ token: String) -> Bool {
        guard let storedToken = sessionToken, isSessionValid() else {
            return false
        }
        return storedToken == token
    }
}

// MARK: - PIN Authentication

final class PINAuthenticationService {
    
    static let shared = PINAuthenticationService()
    
    private let keychainService = "com.bankingapp.pin"
    private let keychainAccount = "userPIN"
    private let maxAttempts = 5
    private var failedAttempts = 0
    private var lockoutUntil: Date?
    
    private init() {}
    
    func setPIN(_ pin: String) throws {
        guard pin.count >= 4 && pin.count <= 6 else {
            throw PINError.invalidPINLength
        }
        
        guard pin.allSatisfy({ $0.isNumber }) else {
            throw PINError.invalidPINFormat
        }
        
        let hashedPIN = EncryptionService.shared.hashData(pin.data(using: .utf8)!)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: keychainAccount,
            kSecValueData as String: hashedPIN.data(using: .utf8)!,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        
        guard status == errSecSuccess else {
            throw PINError.storageError
        }
        
        AuditLogger.shared.log(event: "PIN set successfully")
    }
    
    func verifyPIN(_ pin: String) -> Result<Bool, PINError> {
        if let lockout = lockoutUntil, Date() < lockout {
            return .failure(.accountLocked)
        }
        
        lockoutUntil = nil
        
        let hashedInput = EncryptionService.shared.hashData(pin.data(using: .utf8)!)
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: keychainAccount,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let storedData = result as? Data, let storedHash = String(data: storedData, encoding: .utf8) else {
            return .failure(.pinNotSet)
        }
        
        if hashedInput == storedHash {
            failedAttempts = 0
            AuditLogger.shared.log(event: "PIN verification successful")
            return .success(true)
        } else {
            failedAttempts += 1
            AuditLogger.shared.log(event: "PIN verification failed", details: ["attempt": "\(failedAttempts)"], severity: .warning)
            
            if failedAttempts >= maxAttempts {
                lockoutUntil = Date().addingTimeInterval(300) // 5 minute lockout
                AuditLogger.shared.log(event: "Account locked due to failed PIN attempts", severity: .critical)
                return .failure(.accountLocked)
            }
            
            return .success(false)
        }
    }
    
    enum PINError: Error, LocalizedError {
        case invalidPINLength
        case invalidPINFormat
        case storageError
        case pinNotSet
        case accountLocked
        
        var errorDescription: String? {
            switch self {
            case .invalidPINLength: return "PIN must be 4-6 digits"
            case .invalidPINFormat: return "PIN must contain only digits"
            case .storageError: return "Failed to store PIN securely"
            case .pinNotSet: return "No PIN has been set"
            case .accountLocked: return "Account is temporarily locked. Try again later."
            }
        }
    }
}